@pytest.mark.asyncio
async def test_batch_embed() -> None:
    """Embedding request with multiple input strings returns one embedding object per input."""
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/batch_embed",
    )
    request = EmbeddingRequest.from_json(
        '{"input":["Hello","World"],"model":"text-embedding-3-small"}'
    )

    result = await client.embed(request)
    assert len(result.data) == 2  # noqa: S101
    assert len(result.data[0].embedding) == 5  # noqa: S101


